# Quest Tracker
import json

class Quest:
    def __init__(self, name, reward):
        self.name = name
        self.reward = reward
        self.done = False

    def complete(self):
        self.done = True
        return self.reward

class Hero:
    def __init__(self, name):
        self.name = name
        self.gold = 0
        self.quests = []

    def accept(self, quest):
        self.quests.append(quest)

    def finish(self, quest):
        gold = quest.complete()
        self.gold += gold

    def active_quests(self):
        return [q for q in self.quests
                if not q.done]

    def completed_quests(self):
        return [q for q in self.quests
                if q.done]

def load_quests(path):
    with open(path) as f:
        data = json.load(f)
    return [Quest(q['name'], q['reward'])
            for q in data]
